-
-    // Handle bool
-    if (T == bool) {
-        return value;
-    }
-
-    // Handle slices (including strings)
-    if (info == .pointer and info.pointer.size == .slice) {
-        return value.len > 0;
-    }
-
-    // Handle single-item pointers to arrays (string literals)
